import json
from flask import Flask, request, abort

app = Flask(__name__)
war_room = WarRoomSetup(SLACK_TOKEN, ZoomClient(ZOOM_KEY, ZOOM_SECRET))

@app.post("/webhooks/pagerduty")
def pagerduty_webhook():
    payload = request.get_json(force=True)
    for event in payload.get("messages", []):
        if event["event"] != "incident.trigger":
            continue
        incident = event["incident"]
        severity = _map_urgency(incident["urgency"])
        if severity not in ("SEV1", "SEV2"):
            continue  # SEV3+ use async channel only
        ic_user_id = _resolve_ic(incident["assignments"])
        result = war_room.create_incident_channel(
            severity=severity,
            title=incident["title"],
            ic_user_id=ic_user_id,
        )
        # Confirm back to PagerDuty via annotations
        _annotate_pd_incident(
            incident["id"],
            f'War room: slack://channel?id={result["channel_id"]}'
        )
    return {"ok": True}

def _map_urgency(urgency: str) -> str:
    return {"high": "SEV1", "low": "SEV2"}.get(urgency, "SEV3")
